function solve(points) {
    const MOD = 1e9 + 7;
    const yToX = new Map();

    for (const [x, y] of points) {
        if (!yToX.has(y)) {
            yToX.set(y, []);
        }
        yToX.get(y).push(x);
    }

    // Only consider y values with at least 2 points
    const yList = Array.from(yToX.keys()).filter(y => yToX.get(y).length >= 2);
    yList.sort((a, b) => a - b);
    const n = yList.length;
    if (n < 2) {
        return 0;
    }

    // Precompute the count of pairs for each y
    const pairCounts = [];
    for (const y of yList) {
        const xs = yToX.get(y).sort((a, b) => a - b);
        const m = xs.length;
        const cnt = m * (m - 1) / 2;
        pairCounts.push(cnt % MOD);
    }

    // Precompute prefix sums of pairCounts
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = (prefix[i] + pairCounts[i]) % MOD;
    }

    let total = 0;
    // For each y, multiply its pair count with the sum of pair counts of previous y's
    for (let i = 1; i < n; i++) {
        const currentPairs = pairCounts[i];
        const prevPairsSum = prefix[i];
        total = (total + currentPairs * prevPairsSum) % MOD;
    }

    return total;
}
